UPDATE public.garden_import_queue SET payload = '{"species": "Rambutan", "species_slug": "rambutan", "varieties": [{"name": "Jitlee", "slug": "jitlee", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Singapore, traditional cultivar established pre-1960s", "traits": "Medium-sized fruit (36-45g), round shape, orange-red to red skin with moderate spintern density", "flesh_fruit": "White, thick aril (42% recovery), firm texture, less juicy than other varieties, sweet with subtle acidity (20-21°Brix)", "yield_notes": "Good productivity, early flowering variety", "growing_notes": "One of the main varieties grown in tropical Queensland and Northern Territory. Performs well in humid subtropical conditions with protection from cold. Hardy variety suitable for home gardens. Creamy texture distinguishes it from juicier varieties.", "availability": "Daley''s Fruit Tree Nursery, tropical Queensland nurseries", "sort_order": 0}, {"name": "R134", "slug": "r134", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Malaysia, registered clone", "traits": "Medium-sized fruit (42-45g), ovate shape, bright orange-red skin with good color presentation", "flesh_fruit": "White translucent, thick aril, sweet with hint of rose, firm and juicy (14-15% aril, 6.6-7°Brix)", "yield_notes": "Moderate to good productivity", "growing_notes": "One of the main commercial varieties in tropical Australia. Recommended for Queensland cultivation. Early flowering, adapts well to tropical Queensland conditions. Excellent market variety due to attractive appearance.", "availability": "Queensland commercial nurseries, tropical fruit tree specialists", "sort_order": 1}, {"name": "R156 (Muar Gading)", "slug": "r156-muar-gading", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Muar, Johor, Malaysia - registered early 1960s by Ng Ah Kow", "traits": "Medium fruit (37-60g), round, distinctive ivory/bright yellow skin when ripe, soft pale yellow spinterns, grows 5-6m height", "flesh_fruit": "White translucent, very thick aril (57% recovery), firm, juicy, neutral semi-sweet flavor with mild acidity (22°Brix)", "yield_notes": "Moderate to good", "growing_notes": "Yellow variety popular in Malaysia. One of main varieties in tropical Australia. Moderately vigorous, early ripening. Unique yellow color makes it distinctive in markets. Thinner skin than red varieties. Performs well in tropical Queensland with proper care.", "availability": "Limited in Australia, some tropical Queensland nurseries", "sort_order": 2}, {"name": "R167 (Chai Tow Cheng)", "slug": "r167-chai-tow-cheng", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Malaysia, registered clone", "traits": "Large fruit (44-48g), elongated ovate shape, red peel with prominent spinterns", "flesh_fruit": "White, thick, sweet aril (14-15%, 7°Brix)", "yield_notes": "Good productivity, reliable bearer", "growing_notes": "One of the four main varieties grown commercially in tropical Australia (Queensland and Northern Territory). Commonly used as rootstock due to vigor. Adapts well to tropical Queensland climate with adequate humidity and warmth.", "availability": "Queensland commercial nurseries, Northern Territory growers", "sort_order": 3}, {"name": "Binjai", "slug": "binjai", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Binjai region, North Sumatra, Indonesia - traditional variety", "traits": "Large fruit (45-54g), elongated shape, striking bright red skin, long spinterns (though somewhat sparse), vigorous tree", "flesh_fruit": "White, very thick, soft almost creamy texture, exceptionally sweet with subtle acidity, less watery, freestone tendency", "yield_notes": "High productivity (1200-2000 fruits/tree, 40-70kg), early flowering", "growing_notes": "One of Indonesia''s five leading commercial cultivars. Successfully grown in Australia''s Northern Territory with excellent performance. Prized for large size and rich flavor. Performs best in full tropical conditions but can adapt to warm subtropical areas with protection. Excellent for fresh eating.", "availability": "Some tropical Queensland nurseries, specialty importers", "sort_order": 4}, {"name": "Rongrien (Rong Rien, R191)", "slug": "rongrien-rong-rien-r191", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Thailand, selected near a school in Penang, Malaysia (''Anak Sekolah'' means ''school child'')", "traits": "Medium-large fruit (41-45g), perfectly round shape, bright red skin, long flexible spinterns, vigorous growth", "flesh_fruit": "White, firm and crisp, exceptionally sweet (16-17%, 7-21°Brix), juicy, satisfying bite texture", "yield_notes": "Very high productivity, reliable heavy cropper", "growing_notes": "Most popular commercial variety in Thailand. Grown in tropical Australia with success. Flowers later than other varieties in Northern Territory but early in North Queensland. Excellent for fresh eating and holds up well in fruit salads. Requires pollinator as produces few male flowers.", "availability": "Limited in Brisbane area, available in North Queensland tropical nurseries", "sort_order": 5}, {"name": "R162 (Daun Hijau / Ong Heok)", "slug": "r162-daun-hijau-ong-heok", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Penang, Malaysia", "traits": "Large fruit (36-59g), elongated shape, yellow-red-orange peel, vigorous tree to 7m", "flesh_fruit": "White, very thick (54% recovery), firm, dry, sweet (22°Brix), freestone type", "yield_notes": "High yields, consistent production", "growing_notes": "One of Malaysia''s commercial varieties. Grown experimentally in tropical Australia. Round canopy shape. Sensitive to waterlogging. Suitable for tropical Queensland with well-drained soils.", "availability": "Limited availability, specialist tropical nurseries", "sort_order": 6}, {"name": "Gula Batu (R3)", "slug": "gula-batu-r3", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Malaysia, traditional cultivar", "traits": "Large fruit (54g), ovate shape, red skin", "flesh_fruit": "White, thick (16-17%), sweet like rock sugar (hence name ''sugar rock''), 7.2°Brix", "yield_notes": "Good productivity, performs well as rootstock", "growing_notes": "One of Malaysia''s popular commercial cultivars. Name means ''rock sugar'' in Malay. Used successfully as rootstock in research trials. Adapts to tropical Queensland conditions. Provides higher yields when used as rootstock for other varieties.", "availability": "Limited in Australia, research stations", "sort_order": 7}, {"name": "R9", "slug": "r9", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Malaysia", "traits": "Medium fruit (37g), oval shape, red-orange skin", "flesh_fruit": "White, moderately thick (13%), sweet (7.5°Brix)", "yield_notes": "Moderate production", "growing_notes": "Malaysian variety introduced to Australia. Acceptable in Australian markets due to relatively free testa adherence. Suitable for tropical Queensland cultivation.", "availability": "Limited availability in Queensland", "sort_order": 8}, {"name": "R168", "slug": "r168", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Malaysia", "traits": "Large fruit (49g), oblong shape, red skin", "flesh_fruit": "White, moderately thick (14-15%), 5.1°Brix", "yield_notes": "Good production", "growing_notes": "Malaysian variety found acceptable in Australian markets. Relatively free from testa adherence issue. Suitable for tropical Queensland.", "availability": "Specialist tropical nurseries in Queensland", "sort_order": 9}, {"name": "Arka Coorg Arun 🏆", "slug": "arka-coorg-arun", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "ICAR-IIHR Central Horticultural Experiment Station, Chettalli, Karnataka, India - released Indian variety", "traits": "Medium fruit (4