UPDATE public.garden_import_queue SET payload = '{"species": "Sage", "species_slug": "sage", "varieties": [{"name": "Common Sage (Salvia officinalis) 🏆", "slug": "common-sage-salvia-officinalis", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Mediterranean region (Southern Europe, Northern Africa), cultivated for 2000+ years", "traits": "Woody perennial subshrub, 60-90 cm tall, gray-green velvety leaves, lavender-blue flowers", "flesh_fruit": "", "yield_notes": "High productivity, multiple harvests annually", "growing_notes": "Brisbane climate: Performs well but prefers drier conditions. Requires excellent drainage. Can struggle with high summer humidity - plant in full sun with good air circulation. Tolerates Brisbane''s mild winters excellently. Harvest before flowering for best flavor.", "availability": "Widely available - Herb Cottage, Bunnings, local Brisbane nurseries", "sort_order": 0}, {"name": "Berggarten Sage (S. officinalis ''Berggarten'')", "slug": "berggarten-sage-s-officinalis-berggarten", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Berggarten Mansion, Germany, selected cultivar", "traits": "Compact bush 45-60 cm, larger broader leaves than common sage, rarely blooms", "flesh_fruit": "", "yield_notes": "Excellent leaf production, dense bushy growth", "growing_notes": "Brisbane: Excellent choice. Mildew resistance valuable in humid summers. Full sun required. Stays compact and manageable. Hardy to mild Brisbane winters. One of best performers for subtropical Queensland.", "availability": "Online nurseries, specialty herb suppliers in Queensland", "sort_order": 1}, {"name": "Purple Sage (S. officinalis ''Purpurascens'')", "slug": "purple-sage-s-officinalis-purpurascens", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mediterranean cultivar selection", "traits": "30-45 cm tall, purple-tinged leaves maturing to gray-green, lavender flowers", "flesh_fruit": "", "yield_notes": "Moderate to good, strong flavor", "growing_notes": "Brisbane: Less winter hardy than common sage (Zone 6+). Requires protection in cooler Brisbane areas. Best grown as annual or in containers to move if needed. Full sun essential. Ornamental value high.", "availability": "Herb Cottage, selected nurseries", "sort_order": 2}, {"name": "Tricolor Sage (S. officinalis ''Tricolor'')", "slug": "tricolor-sage-s-officinalis-tricolor", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mediterranean cultivar", "traits": "30-45 cm, variegated green, white, pink leaves, compact growth", "flesh_fruit": "", "yield_notes": "Moderate, milder flavor than common sage", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Golden Sage (S. officinalis ''Icterina'')", "slug": "golden-sage-s-officinalis-icterina", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mediterranean cultivar selection", "traits": "30-45 cm, gold and green variegated foliage, ornamental", "flesh_fruit": "", "yield_notes": "Good, slightly milder flavor, citrus notes in well-limed soil", "growing_notes": "Brisbane: Hardy to Zone 6, suitable for Brisbane climate. Slow-growing advantage for low-maintenance gardens. Requires bright sun for best color. Tolerates subtropical conditions better than Tricolor.", "availability": "Nurseries, online herb suppliers", "sort_order": 4}, {"name": "Holt''s Mammoth Sage (S. officinalis ''Holt''s Mammoth'')", "slug": "holt-s-mammoth-sage-s-officinalis-holt-s-mammoth", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Commercial selection for large leaf production", "traits": "75-90 cm tall, vigorous fast growth, extra-large leaves 10-12 cm", "flesh_fruit": "", "yield_notes": "Very high, commercial-quality production", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Dwarf Sage (S. officinalis ''Compacta'')", "slug": "dwarf-sage-s-officinalis-compacta", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Compact cultivar selection", "traits": "20-25 cm tall, miniature compact form, small narrow leaves", "flesh_fruit": "", "yield_notes": "Moderate for size, slower growth", "growing_notes": "Brisbane: Ideal for containers and small Brisbane gardens. Excellent air circulation due to compact size reduces humidity issues. Perfect for apartment balconies. Zone 4-10 hardy. Propagated by cuttings only.", "availability": "Specialist nurseries, propagated material", "sort_order": 6}, {"name": "Pineapple Sage (Salvia elegans)", "slug": "pineapple-sage-salvia-elegans", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico and Guatemala highlands", "traits": "90-150 cm tall, bright green foliage, scarlet-red tubular flowers late summer-autumn", "flesh_fruit": "", "yield_notes": "High, rapid growth in warm conditions", "growing_notes": "Brisbane: EXCELLENT for subtropical Brisbane. Heat and humidity tolerant. Attracts hummingbirds and bees. Tender perennial - may die back in cold winters but resprouts. Frost-sensitive. Full sun to part shade. One of best sages for Brisbane climate.", "availability": "Common in Brisbane nurseries, Herb Cottage", "sort_order": 7}, {"name": "Mexican Bush Sage (Salvia leucantha)", "slug": "mexican-bush-sage-salvia-leucantha", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico and Central America", "traits": "90-120 cm tall, dense shrubby growth, velvety purple and white flower spikes", "flesh_fruit": "", "yield_notes": "Primarily ornamental, moderate leaf production", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "Scarlet Sage (Salvia splendens)", "slug": "scarlet-sage-salvia-splendens", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Brazil, tropical Americas", "traits": "30-90 cm, brilliant red flower spikes (also pink, white, purple cultivars)", "flesh_fruit": "", "yield_notes": "Ornamental, continuous flowering", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "Cleveland Sage (Salvia clevelandii)", "slug": "cleveland-sage-salvia-clevelandii", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "California and Baja California", "traits": "60-150 cm, aromatic gray-green foliage, lavender-purple flowers", "flesh_fruit": "", "yield_notes": "Good ornamental and culinary use", "growing_notes": "Brisbane: Moderate success. Prefers drier Mediterranean climate but adaptable. Requires excellent drainage. Drought-tolerant - important in Brisbane''s dry spells. Prune after flowering. May need protection from extreme humidity.", "availability": "Online Australian native/water-wise nurseries", "sort_order": 10}, {"name": "Mealycup Sage (Salvia farinacea)", "slug": "mealycup-sage-salvia-farinacea", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico, Texas, New Mexico", "traits": "60-120 cm, blue-violet flower spikes with powdery appearance", "flesh_fruit": "", "yield_notes": "Primarily ornamental bedding plant", "growing_notes": "Brisbane: Good performer. Grown as annual in bedding displays. Tolerates Brisbane heat. Full sun to partial shade beneficial. Popular cultivars ''Victoria Blue'', ''Empire Purple''. Attracts bees and butterflies. Self-seeds readily.", "availability": "Common in Brisbane nurseries as bedding plants", "sort_order": 11}, {"name": "White Sage (Salvia apiana)", "slug": "white-sage-salvia-apiana", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southern California, Baja California", "traits": "90-150 cm tall, silvery-white foliage, white flowers with lavender spots", "flesh_fruit": "", "yield_notes": "Slow-growing, 2-3 years to maturity", "growing_notes": "Brisbane: CHALLENGING. Prefers very dry conditions - struggles with Brisbane humidity. Requires perfect drainage and minimal summer water. May rot in wet winters. Best grown in large containers with controlled watering. Zone 8-10 but humidity is limiting factor. Sacred ceremonial use - harvest responsibly.", "availability": "Specialty herb nurseries, online suppliers", "sort_order": 12}, {"name": "Clary Sage (Salvia sclarea) 🏆", "slug": "clary-sage-salvia-sclarea", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Mediterranean, Central Asia, cultivated since ancient times", "traits": "60-120 cm, biennial or short-lived perennial, large textured leaves, showy flower spikes", "flesh_fruit": "", "yield_notes": "Good, primarily grown for essential oil and ornamental value", "growing_notes": "Brisbane: Moderate success. Requires cold period (3+ months) for flowering - may not flower reliably in Brisbane. More suitable for cooler Queensland regions (Toowoomba, Stanthorpe). Well-drained soil essential. Cultivar ''Turkestanica'' more heat-tolerant.", "availability": "Herb nurseries, essential oil plant suppliers", "sort_order": 13}, {"name": "Common Sage (Salvia officinalis) 🏆", "slug": "common-sage-salvia-officinalis", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Mediterranean region", "traits": "60-90 cm woody perennial, gray-green leaves, lavender flowers", "flesh_fruit": "", "yield_notes": "Variable in tropical conditions", "growing_notes": "Kerala: VERY CHALLENGING. Does not tolerate tropical monsoon climate well. Hates wet feet and high humidity. If attempted: Grow in large containers with excellent drainage, bring under cover during heavy monsoons. May survive as short-lived annual. Not recommended for Kerala lowlands. Better suited to cooler Indian hill stations.", "availability": "Limited - import seeds, very rare in Kerala nurseries", "sort_order": 0}, {"name": "Clary Sage (Salvia sclarea) 🏆", "slug": "clary-sage-salvia-sclarea", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Mediterranean and Central Asia", "traits": "Biennial herb with large leaves, showy flower spikes", "flesh_fruit": "", "yield_notes": "Poor in tropical monsoon", "growing_notes": "Kerala: NOT SUITABLE. Successfully introduced to subtropical North Indian plains as winter annual crop (Kashmir valley produces small amounts). Requires cold period for flowering. Heavy monsoon rains cause rot. Not adapted to Kerala climate. Best grown in cooler Indian regions.", "availability": "Not available in Kerala; Kashmir/North India sources only", "sort_order": 1}, {"name": "Pineapple Sage (Salvia elegans)", "slug": "pineapple-sage-salvia-elegans", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Mexico and Guatemala highlands (1800-2700m elevation)", "traits": "90-150 cm perennial, bright green leaves, scarlet tubular flowers", "flesh_fruit": "", "yield_notes": "Good in suitable conditions", "growing_notes": "Kerala: BEST OPTION for tropical Kerala. Highly heat and humidity tolerant. Native to tropical regions. Frost-sensitive (perfect for Kerala - no frost). Morning sun with afternoon shade ideal. Requires regular moisture - suits monsoon climate. Protect from heavy downpours. Container growing recommended for drainage control. Most likely sage to succeed in Thiruvalla area.", "availability": "May be available through specialty herb suppliers; import seeds possible", "sort_order": 2}, {"name": "Mexican Bush Sage (Salvia leucantha)", "slug": "mexican-bush-sage-salvia-leucantha", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Mexico and Central America", "traits": "90-120 cm evergreen shrub, velvety purple flowers", "flesh_fruit": "", "yield_notes": "Ornamental value", "growing_notes": "Kerala: GOOD POTENTIAL. Drought-tolerant once established - handles dry periods between monsoons. Tropical to subtropical origin suits Kerala. Requires excellent drainage during monsoons. Plant on slopes or raised beds. Full sun. May perform well in Thiruvalla if protected from waterlogging. Zones 8-10.", "availability": "Rare in Kerala; seeds may be imported", "sort_order": 3}, {"name": "Scarlet Sage (Salvia splendens)", "slug": "scarlet-sage-salvia-splendens", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Brazil, tropical Americas", "traits": "30-90 cm, brilliant red flowers year-round in tropics", "flesh_fruit": "", "yield_notes": "Excellent ornamental performance", "growing_notes": "Kerala: EXCELLENT CHOICE. Native to tropical climate - ideally suited for Kerala. Thrives in heat and humidity. Self-seeds prolifically. Year-round flowering in tropical conditions. Grows well in sun or partial shade. Perfect for Kerala monsoon climate. One of the best Salvia species for tropical India.", "availability": "May be available in Kerala nurseries as ornamental; seeds can be sourced", "sort_order": 4}, {"name": "Mealycup Sage (Salvia farinacea)", "slug": "mealycup-sage-salvia-farinacea", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Mexico, Texas plains", "traits": "60-120 cm, blue-violet flower spikes", "flesh_fruit": "", "yield_notes": "Ornamental", "growing_notes": "Kerala: MODERATE SUCCESS POSSIBLE. Heat-tolerant but may become leggy with too much shade or water. Prefers full sun to partial shade. Requires good drainage - critical during monsoons. Grown as annual in most areas. May reseed. Benefits from afternoon shade in intense Kerala heat.", "availability": "Import seeds; rare in Indian nurseries", "sort_order": 5}, {"name": "Grape Scented Sage (Salvia melissodora)", "slug": "grape-scented-sage-salvia-melissodora", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Mexico", "traits": "150-180 cm tall, open shrub, light purple flowers", "flesh_fruit": "", "yield_notes": "High biomass, tea production", "growing_notes": "Kerala: GOOD POTENTIAL. Mexican origin suggests heat tolerance. Large size provides good harvest. Late summer to frost flowering (continuous in Kerala). Tea use valuable. Requires space. Good drainage essential. May adapt to Kerala conditions with proper site selection.", "availability": "Import seeds; specialty sources", "sort_order": 6}, {"name": "Fruit Sage (Salvia dorisiana)", "slug": "fruit-sage-salvia-dorisiana", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Honduras, tropical Central America", "traits": "90-120 cm, magenta-pink winter flowers, fruit salad aroma", "flesh_fruit": "", "yield_notes": "Good, aromatic tea herb", "growing_notes": "Kerala: EXCELLENT OPTION. Tropical origin from Central America - well-suited to Kerala climate. Tolerates semi-shade (benefits afternoon shade in Kerala heat). Winter flowering in native habitat may mean year-round flowers in Kerala. Highly aromatic for tea. One of best tropical Salvias for monsoon regions.", "availability": "Specialty herb imports; rare but suitable for Kerala", "sort_order": 7}], "variety_count": 22}'::jsonb,
  variety_count = 22, status = 'parsed'
WHERE source_path = 'brainstorm-inbox/import-payloads/sage.json';

