UPDATE public.garden_import_queue SET payload = '{"species": "Sorghum", "species_slug": "sorghum", "varieties": [{"name": "MR Buster", "slug": "mr-buster", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Pacific Seeds, Australia, 1991", "traits": "Medium maturity, high tillering, industry benchmark for 32 years, excellent midge resistance (MR), good grain size", "flesh_fruit": "", "yield_notes": "Consistently high yields 3.5-5.5 t/ha, excellent standability", "growing_notes": "Bred by Neil Muller. Dominated Queensland sorghum for decades. Excellent adaptation to subtropical Queensland conditions, performs in both dryland and irrigated systems. Extremely high and consistent grain yields. Good heat tolerance. Still widely grown by conservative growers who trust proven performance.", "availability": "Pacific Seeds, widely available Queensland", "sort_order": 0}, {"name": "Resolute", "slug": "resolute", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Pacific Seeds, Australia, 2020s", "traits": "Medium maturity, improved pre & post flowering stress tolerance, limited tiller production, excellent stability", "flesh_fruit": "", "yield_notes": "Consistently high across locations 3.5-4.5 t/ha, outperformed MR Buster in trials", "growing_notes": "Bred to surpass MR Buster. Won 1st place at 2023 RASQ Toowoomba Show dryland category. Excellent subtropical Queensland adaptation, particularly in Central Highlands. Superior stress tolerance makes it ideal for variable rainfall patterns. Performs well in tight finishes. Strong all-around hybrid for Brisbane region.", "availability": "Pacific Seeds, Queensland dealers", "sort_order": 1}, {"name": "Halifax", "slug": "halifax", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Pacific Seeds, Australia, 2020s", "traits": "Similar maturity to Resolute, improved stress tolerance, consistent performer across environments", "flesh_fruit": "", "yield_notes": "High yielding 3.4-6.8 t/ha depending on conditions, ranked top 3 in most Queensland trial sites", "growing_notes": "Also surpasses MR Buster with improved stress tolerance. Topped multiple NVT trial locations including Billa Billa (3.17 t/ha), Condamine (1.8 t/ha), Rolleston (3.79 t/ha), and Pampas (6.8 t/ha). Excellent heat and humidity tolerance. Well-suited to Brisbane''s subtropical summer conditions. Versatile across soil types.", "availability": "Pacific Seeds, Queensland", "sort_order": 2}, {"name": "MR Taurus", "slug": "mr-taurus", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Pacific Seeds, Australia", "traits": "Medium maturity, midge resistant, good agronomics", "flesh_fruit": "", "yield_notes": "Consistent mid-range performer", "growing_notes": "Reliable Queensland hybrid for subtropical conditions. Good midge resistance important for coastal regions. Handles Brisbane humidity well.", "availability": "Pacific Seeds", "sort_order": 3}, {"name": "MR Bazley", "slug": "mr-bazley", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Pacific Seeds, Australia", "traits": "Midge resistant, proven Queensland performer", "flesh_fruit": "", "yield_notes": "Stable yields in subtropical environments", "growing_notes": "Adapted to Brisbane region conditions. Good heat tolerance for subtropical summers.", "availability": "Pacific Seeds, Queensland", "sort_order": 4}, {"name": "Sentinel IG", "slug": "sentinel-ig", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Pacific Seeds, Australia", "traits": "Herbicide tolerant (Imidazolinone), good agronomics", "flesh_fruit": "", "yield_notes": "Good yielding with weed management advantages", "growing_notes": "Imidazolinone tolerance allows better weed control in Queensland conditions. Suitable for Brisbane subtropical climate.", "availability": "Pacific Seeds", "sort_order": 5}, {"name": "A66", "slug": "a66", "lineage_type": "hybrid", "climate_slug": "humid-su