UPDATE public.garden_import_queue SET payload = '{"species": "Soursop", "species_slug": "soursop", "varieties": [{"name": "Seedling Selections (Queensland-Adapted)", "slug": "seedling-selections-queensland-adapted", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Queensland, Australia (grown from diverse tropical seed sources)", "traits": "Heart-shaped fruits, dark green skin with soft fleshy spines, fruit size 10-30cm long, weight 1.5-4kg", "flesh_fruit": "White, juicy, slightly fibrous, creamy texture with sweet-tart flavor combining strawberry, pineapple and citrus notes", "yield_notes": "12-24 fruits per tree annually, fruit production begins 2-3 years from seed in tropical conditions, 3-5 years in subtropics", "growing_notes": "Requires frost-free site with protection from cold winds. In Queensland, well-watered trees reach 4.5-5.5m in 6-7 years. Fruiting season begins April. Sensitive to temperatures below 5°C when young, requiring protection until established. Main pest is mealybug on fruits. Prefers deep, well-drained, semi-dry soil.", "availability": "Daley''s Fruit Tree Nursery, Fruitopia Nursery Brisbane, Ross Creek Tropicals Gympie, Sunshine Coast nurseries", "sort_order": 0}, {"name": "Grafted Kyogle Selection", "slug": "grafted-kyogle-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Kyogle, New South Wales, Australia (subtropical selection)", "traits": "Medium-large fruit, heart-shaped, green skin, proven performer in marginal subtropical climate", "flesh_fruit": "White, juicy with sweet lemony taste (not sour like lemon), firm texture, less fibrous than seedlings", "yield_notes": "Good crop production, multiple fruits per season, bears within 2-3 years of grafting", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Golden/Yellow Soursop Selection", "slug": "golden-yellow-soursop-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Rare selection available in Australian subtropical nurseries", "traits": "Large fruit, golden-yellow when ripe (distinguishing feature), spiny green skin that yellows at maturity", "flesh_fruit": "Sweet and aromatic, perfect blend of tropical fruits with berry hint, less acidic than standard green varieties", "yield_notes": "Good producer with proper care, typical soursop yield range", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Smooth Flesh Selection", "slug": "smooth-flesh-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Queensland selection grown from smooth-fleshed variety", "traits": "Heart-shaped fruit, typical rough green skin with soft spines", "flesh_fruit": "Notable for smoother, less fibrous flesh texture, juicy and slightly acid, creamy consistency", "yield_notes": "Standard soursop productivity", "growing_notes": "Seedling selection specifically chosen for superior flesh texture. Excellent for fresh consumption and processing. Superb when pureed with vanilla ice cream. Requires subtropical to tropical climate with frost protection.", "availability": "Daley''s Fruit Tree Nursery", "sort_order": 3}, {"name": "Giant South American Selection", "slug": "giant-south-american-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "South American seed-grown selection", "traits": "Large conical fruits, typically 7kg+, specimens exceeding 10kg possible on established trees", "flesh_fruit": "Firm, white, less fibrous than other commercially available varieties", "yield_notes": "Large individual fruit size compensates for typical soursop shy-bearing habit", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Sunshine Coast Grafted Selection", "slug": "sunshine-coast-grafted-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Sunshine Coast, Queensland selection", "traits": "Heart-shaped fruit, rough green skin with soft fleshy spines", "flesh_fruit": "Juicy, slightly acid, producing rich creamy thirst-quenching juice", "yield_notes": "Good cropping history in Sunshine Coast conditions", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Mountain Soursop (Annona montana)", "slug": "mountain-soursop-annona-montana", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Central and South America, naturalized in various tropical regions", "traits": "Round fruit with pale green-yellow skin when ripe, less spiky than regular soursop, fruit 10-15cm diameter", "flesh_fruit": "Lemon-colored, smooth flesh with milder flavor than regular soursop, somewhat inferior quality but acceptable", "yield_notes": "Produces within 2-3 years from seed, reliable bearer", "growing_notes": "MUCH HARDIER than regular soursop - tolerates temperatures down to -2°C, making it the BEST CHOICE for marginal Brisbane areas. Will tolerate more cold than Annona muricata and can be used as rootstock for grafting regular soursop in colder regions. Adaptable to wide range of soils and dry conditions. Can grow in full sun or part shade, reaching 8m height.", "availability": "Daley''s Fruit Tree Nursery, specialist subtropical nurseries", "sort_order": 6}, {"name": "Mullatha / Mullu Chakka (Indian Common) 🌏", "slug": "mullatha-mullu-chakka-indian-common", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Indigenous to South India, widely cultivated in Kerala, Tamil Nadu, Karnataka, Andhra Pradesh", "traits": "Large oval to heart-shaped fruits, dark green leathery skin with soft protruding spines, fruit weight 2-6kg", "flesh_fruit": "White, creamy, fibrous segments surrounding pithy core, sweet-sour flavor with musky aroma, contains 30-200 black seeds", "yield_notes": "Continuous flowering and fruiting, main season April-October in India, 12-24 fruits per tree", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Sweet Type (Sirsak Ratu - Indonesian influence)", "slug": "sweet-type-sirsak-ratu-indonesian-influence", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Southeast Asian selection, cultivated in Kerala through historical trade connections", "traits": "Small to medium fruit, few-seeded, typically 1-2kg", "flesh_fruit": "Sub-acid flavor (lower acidity), sweeter than common types, preferred for fresh eating", "yield_notes": "Moderate productivity, fewer but sweeter fruits", "growing_notes": "Similar to sweet types grown in Indonesia and Philippines. Predominant in a few Kerala localities. Best for fresh consumption. Excellent adaptation to tropical monsoon conditions with high humidity during fruit set. Thrives in Kerala''s warm temperatures (21-32°C).", "availability": "Specialty Kerala nurseries, inquire at local fruit tree sellers", "sort_order": 1}, {"name": "Aguinaldo Type (Philippine Introduction)", "slug": "aguinaldo-type-philippine-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Philippines, introduced to India through tropical fruit exchange programs", "traits": "Medium fruit approximately 1kg, yellow-green peel", "flesh_fruit": "Juicy, sub-acid (moderately acidic), 78% of fruit weight is edible, approximately 70 seeds per fruit", "yield_notes": "Good edible portion ratio, reliable cropper in tropical conditions", "growing_notes": "Part of Philippines'' major soursop production heritage (Western Visayas, Central Luzon leading regions). Adapted to similar tropical monsoon climate as Kerala. Sub-acid types excellent for both fresh consumption and processing. Can be consumed fresh or used for juices and desserts.", "availability": "May be available through specialty importers or agricultural research stations in Kerala", "sort_order": 2}, {"name": "Davao Type (Philippine Introduction)", "slug": "davao-type-philippine-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Davao region, Philippines", "traits": "Larger fruit approximately 1.7kg, light green peel", "flesh_fruit": "Moderately juicy, pleasantly sub-acid, 82% of fruit weight is edible, approximately 82 seeds per fruit", "yield_notes": "Excellent edible portion (82%), good size fruit, reliable bearer", "growing_notes": "Higher edible percentage than Aguinaldo type. Philippines is major producer with similar tropical climate to Kerala. Mindanao region (including Davao) known for quality soursop. Excellent for Kerala''s climate with high temperatures and humidity. Pleasant sub-acid flavor makes it versatile for fresh eating and processing.", "availability": "May be available through specialty importers or agricultural research stations in Kerala", "sort_order": 3}, {"name": "Seedling Selections (Kerala-Adapted)", "slug": "seedling-selections-kerala-adapted", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Local Kerala selections from superior mother trees", "traits": "Variable, ranging from round to heart-shaped to angular, skin color from dark green to yellow-green at maturity", "flesh_fruit": "Quality varies from soft and juicy to firm and dry, flavor ranges from sweet to sub-acid to acid", "yield_notes": "Variable but adapted to local conditions, fruits within 2-3 years", "growing_notes": "Kerala has diverse soursop genetic material grown on limited scale. Trees grow wild and cultivated in Southern India. Excellent adaptation to tropical monsoon climate. Thrives on coastal regions with tropical weather. Prefers well-drained, loamy soil with high humidity during fruit set. Continuous flowering with main season April-October.", "availability": "Local Kerala nurseries, home garden exchanges, Greens of Kerala, Golden Hills Farm", "sort_order": 4}, {"name": "Crioula (Brazilian Introduction) 🏆", "slug": "crioula-brazilian-introduction", "lineage_type": "heirloom", "climate_slug": "tropical-mo