UPDATE public.garden_import_queue SET payload = '{"species": "Squash", "species_slug": "squash", "varieties": [{"name": "Black Beauty", "slug": "black-beauty", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "United States, pre-1950s", "traits": "Dark green, almost black skin; cylindrical shape; 6-8 inches at harvest", "flesh_fruit": "Pale white, tender, mild flavor", "yield_notes": "Very high; prolific producer", "growing_notes": "Excellent for Brisbane''s subtropical climate. Bush-type plant, heat tolerant, handles humidity well. Most popular green zucchini. Matures 50-63 days.", "availability": "Widely available in Queensland nurseries and seed suppliers", "sort_order": 0}, {"name": "Costata Romanesco", "slug": "costata-romanesco", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Italy (Rome region), 1800s", "traits": "Dark green with light green striping; prominent ribs; 12-18 inches", "flesh_fruit": "Dense, nutty flavor; tender even when large", "yield_notes": "Moderate; produces large male blossoms for cooking", "growing_notes": "Superior flavor, suited to Brisbane climate. Handles heat well, traditional Italian heirloom. Best picked at 4-6 inches. Some parthenocarpic ability. Matures 52-60 days.", "availability": "Specialty seed companies, heirloom suppliers in Australia", "sort_order": 1}, {"name": "Cocozelle", "slug": "cocozelle", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Naples, Italy, 1880s", "traits": "Dark green with light green stripes; long cylindrical; slight ribbing", "flesh_fruit": "Dense, slightly nutty, firm texture", "yield_notes": "Very productive throughout season", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Grey Zucchini", "slug": "grey-zucchini", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico/Southwest USA", "traits": "Gray mottled skin; cylindrical shape; 6-8 inches harvest", "flesh_fruit": "Firm, mild, crisp and tender", "yield_notes": "High quality shipper, excellent yields", "growing_notes": "Popular in subtropical regions. Heat tolerant, handles Brisbane humidity. Semi-spiny bush type. Matures 55 days.", "availability": "Queensland seed suppliers", "sort_order": 3}, {"name": "Round Zucchini (Ronde de Nice)", "slug": "round-zucchini-ronde-de-nice", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Nice, France", "traits": "Round shape, 2-4 inches diameter; mottled green coloring", "flesh_fruit": "Nutty flavor, tender flesh", "yield_notes": "Very productive; flower to fruit in one week", "growing_notes": "Excellent for Brisbane, perfect for stuffing. Compact plant, ideal for containers. Harvest at 2-3 inch diameter. Matures 45-50 days.", "availability": "Specialty heirloom suppliers", "sort_order": 4}, {"name": "Early Summer Crookneck", "slug": "early-summer-crookneck", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Colonial America, pre-1800s", "traits": "Curved neck, yellow bumpy skin; 6 inches at harvest", "flesh_fruit": "Creamy white, buttery flavor, meaty texture", "yield_notes": "Very prolific bush type", "growing_notes": "One of oldest squash types, pre-European contact. Excellent for Brisbane subtropical climate. Heat tolerant, handles humidity. Considered best-tasting yellow crookneck. Matures 50-60 days.", "availability": "Common in Queensland nurseries and seed racks", "sort_order": 5}, {"name": "Early Prolific Straightneck", "slug": "early-prolific-straightneck", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "United States, 1938 (Ferry Morse)", "traits": "Straight neck, creamy yellow, smooth skin; 6-8 inches", "flesh_fruit": "Fine texture, smooth, mild flavor", "yield_notes": "Very productive, early producer", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "Golden Summer Crookneck", "slug": "golden-summer-crookneck", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Early 1800s America", "traits": "Golden yellow, curved neck, warted skin when mature", "flesh_fruit": "Tender, sweet, creamy texture", "yield_notes": "Excellent yields, scads of fruit", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Early White Bush Scallop", "slug": "early-white-bush-scallop", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Pre-1700s, one of oldest squash varieties", "traits": "Pale green to white, scalloped edges, 4-6 inches", "flesh_fruit": "Fine textured, tender, mild flavor", "yield_notes": "Very productive, bush-type", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "Benning''s Green Tint", "slug": "benning-s-green-tint", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Washington DC (Benning), 1914, developed by Charles N. Farr", "traits": "Pale green to white, scalloped, 2-3 inches ideal", "flesh_fruit": "Fine-textured, creamy, excellent flavor", "yield_notes": "Very high yields, early maturing", "growing_notes": "Rated best-tasting summer squash by many. Performs excellently in Brisbane''s subtropical climate. Compact productive plants. Matures 50-55 days.", "availability": "Heirloom suppliers, organic seed companies", "sort_order": 9}, {"name": "Yellow Bush Scallop", "slug": "yellow-bush-scallop", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "United States, 1800s", "traits": "Golden yellow, scalloped edges, 3-4 inches", "flesh_fruit": "Buttery, mild, tender texture", "yield_notes": "Productive, decorative", "growing_notes": "Colorful addition to Brisbane gardens. Bush habit, heat tolerant. Decorative and delicious. Matures 50-54 days.", "availability": "Seed blends and heirloom collections", "sort_order": 10}, {"name": "Sunburst", "slug": "sunburst", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "AAS Winner 1985", "traits": "Bright yellow, scalloped, 2-3 inches ideal", "flesh_fruit": "Buttery flavor, tender texture", "yield_notes": "Prolific, early maturing", "growing_notes": "Powdery mildew resistant - excellent for Brisbane humidity. Award-winning hybrid. Early and productive. Matures 50-52 days.", "availability": "Widely available in Queensland", "sort_order": 11}, {"name": "Waltham Butternut", "slug": "waltham-butternut", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Waltham, Massachusetts, 1960s by Robert Young; AAS Winner 1970", "traits": "Tan skin, bell-shaped, straight cylindrical neck; 9 inches long, 4-6 lbs", "flesh_fruit": "Deep orange, dry, sweet nutty flavor, smooth texture", "yield_notes": "High-yielding vines, small seed cavity", "growing_notes": "Most popular butternut, suitable for Brisbane if started early. Requires warm season. Resistant to squash vine borers. Excellent keeper (5+ months). Best flavor after 2 months storage. Matures 85-110 days.", "availability": "Widely available throughout Australia", "sort_order": 12}, {"name": "Table Queen Acorn", "slug": "table-queen-acorn", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Iowa Seed Company, 1913; descended from Arikara Indian squash 1800s; AAS Winner 1939", "traits": "Dark green, acorn-shaped, deeply ribbed, 4-5.5 inches, 1.5 lbs", "flesh_fruit": "Golden yellow (turns orange in storage), sweet, fine-textured, dry and thick", "yield_notes": "Productive, compact vining", "growing_notes": "Sets standard for acorn squash. Suitable for Brisbane with early start. Excellent for baking. Good storage capability. Matures 75-90 days.", "availability": "Common in Australian nurseries", "sort_order": 13}, {"name": "Bottle Gourd (Lauki, Doodhi, Sorakkai) 🏆", "slug": "bottle-gourd-lauki-doodhi-sorakkai", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Ancient cultivation in India, traditional throughout Kerala", "traits": "Light green, elongated or bulbous shape; various sizes (bottle-shaped or long cylindrical)", "flesh_fruit": "White, tender, mild flavor, juicy texture", "yield_notes": "Very productive vining plant", "growing_notes": "Perfectly adapted to Kerala''s monsoon climate. Thrives in high humidity and heat. Grows during summer and monsoon seasons. Essential vegetable in Kerala cuisine. Cooling properties valued in Ayurveda. Matures 60-65 days.", "availability": "Universally available in Kerala - local nurseries, seed shops, agricultural markets", "sort_order": 0}, {"name": "Ridge Gourd (Torai, Peerkangai, Jhinga) 🏆", "slug": "ridge-gourd-torai-peerkangai-jhinga", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Traditional throughout India, especially South India and Kerala", "traits": "Long cylindrical with prominent vertical ridges; dark green skin; 12-18 inches", "flesh_fruit": "Spongy white flesh, mild flavor, tender when young", "yield_notes": "Highly productive in tropical climate", "growing_notes": "Thrives in Kerala''s monsoon conditions. Loves warm, sunny, humid environments. Essential in Kerala cooking - curries and stir-fries. Blood purifier, rich in vitamins C and A. Excellent fiber source. Grows year-round in tropical climate.", "availability": "Widely available throughout Kerala - every local market and nursery", "sort_order": 1}, {"name": "Ash Gourd (Petha, Kumbalanga, Neer Poosanikai) 🏆", "slug": "ash-gourd-petha-kumbalanga-neer-poosanikai", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to Southern Asia, traditional in Kerala and South India", "traits": "Large, round or oblong; pale green skin with white waxy coating; 10-40 lbs", "flesh_fruit": "White, mildly sweet like cucumber, crunchy texture", "yield_notes": "Large fruits, moderate yields on vines", "growing_notes": "Perfect for Kerala''s tropical climate. Warm-season crop loving heat. Highly valued in Ayurvedic medicine for cooling properties. Combats acidity, ulcers, keeps gut healthy. Used in curries, pickles, candies. Excellent storage (months). Grown throughout South India.", "availability": "Common throughout Kerala markets and agricultural suppliers", "sort_order": 2}, {"name": "Snake Gourd (Chichinda, Padwal) 🏆", "slug": "snake-gourd-chichinda-padwal", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to South India, traditional in Kerala cuisine", "traits": "Very long (up to 150cm), slender, twisted like snake; light green with white stripes", "flesh_fruit": "Mild, slightly sweet, soft texture when cooked", "yield_notes": "Prolific in hot humid conditions", "growing_notes": "Thrives in Kerala''s hot and humid tropical climate. Requires trellis support. Popular in Kerala sambar and stir-fries. Fringed white flowers open at night. Harvest immature fruits before fibrous. Strengthens respiratory system, aids weight loss. Available during monsoon season.", "availability": "Common in Kerala - local markets and agricultural stores", "sort_order": 3}, {"name": "Bitter Gourd (Karela, Pavakka) 🏆", "slug": "bitter-gourd-karela-pavakka", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to Kerala and tropical regions of India", "traits": "Bumpy, spiky exterior; oblong shape; dark to light green", "flesh_fruit": "Distinctly bitter taste, crisp texture", "yield_notes": "Abundant on 10-15 ft vines", "growing_notes": "Staple in Kerala kitchen gardens. Thrives in tropical climate. Excellent for managing blood sugar levels. Rich in iron, beta-carotene, vitamins. Valued in Ayurveda for blood purification. Anti-inflammatory properties. Grows throughout summer season in Kerala.", "availability": "Universally available - every Kerala market and nursery", "sort_order": 4}, {"name": "Apple Gourd / Tinda (Indian Squash) 🌱", "slug": "apple-gourd-tinda-indian-squash", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to India, popular in South Asia", "traits": "Small, round or oval; green color; slight thorny surface; apple-sized", "flesh_fruit": "Mild flavor, takes on spice flavors", "yield_notes": "Good yields on compact vines", "growing_notes": "Well-adapted to tropical monsoon climate. Loves humid and hot conditions. Vines grow 1-2 meters. Can be grown in containers with vertical support. Matures 60-70 days. Popular summer vegetable in Kerala.", "availability": "Available in Kerala markets during summer season", "sort_order": 5}, {"name": "Yellow Crookneck Squash", "slug": "yellow-crookneck-squash", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Colonial America", "traits": "Yellow, curved neck, warted when mature", "flesh_fruit": "Pale yellow, buttery flavor", "yield_notes": "Productive in warm climates", "growing_notes": "Can adapt to Kerala''s tropical climate with good drainage. Needs protection from heavy monsoon rains. Best planted after main monsoon period. Heat tolerant. Harvest when 6 inches. Matures 50-60 days.", "availability": "Specialty seed suppliers in India, international seed companies", "sort_order": 6}, {"name": "Black Beauty Zucchini", "slug": "black-beauty-zucchini", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "United States", "traits": "Dark green, cylindrical, 6-8 inches", "flesh_fruit": "White, tender, mild", "yield_notes": "Highly productive", "growing_notes": "Can be grown in Kerala with proper management. Needs well-drained soil to prevent fungal issues in high humidity. Best grown in drier months (December-March). Requires regular harvest. Popular for international cooking. Matures 50-55 days.", "availability": "Select garden centers in Kerala, online seed suppliers", "sort_order": 7}], "variety_count": 22}'::jsonb,
  variety_count = 22, status = 'parsed'
WHERE source_path = 'brainstorm-inbox/import-payloads/squash.json';

UPDATE public.garden_import_queue SET payload = '{"species": "Starfruit", "species_slug": "starfruit", "varieties": [{"name": "Arkin", "slug": "arkin", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Florida, USA, 1960s-1970s. Developed by Morris Arkin in Coral Gables.", "traits": "Uniform fruit 10-13cm long, bright yellow to yellow-orange skin and flesh. Small wings. Smooth, waxy surface.", "flesh_fruit": "Very sweet, juicy, firm, crisp texture. Few seeds. High sugar content. Low oxalic acid (80% less than tart varieties).", "yield_notes": "Very heavy and consistent cropper. Leading commercial cultivar representing 98% of South Florida acreage.", "growing_notes": "Excellent subtropical adaptation. Partially self-fertile. Good cold tolerance for mature trees. Well-suited to Brisbane''s climate. Keeps and ships well. Available from most Australian nurseries.", "availability": "Widely available at Daley''s Fruit Tree Nursery (NSW/QLD), Fruitopia Nursery (Brisbane), Ross Creek Tropicals, Fruit Tree Cottage, and most Queensland specialty nurseries.", "sort_order": 0}, {"name": "Fwang Tung (Kwang Tung)", "slug": "fwang-tung-kwang-tung", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Thailand, cultivated for 50+ years", "traits": "Large fruit 13-20cm long. Bright yellow skin with slight green tint. Pale yellow flesh. Beautiful star shape when sliced.", "flesh_fruit": "Sweet with low acidity, firm, juicy. Few seeds. Excellent dessert quality.", "yield_notes": "Productive and reliable. Self-fertile.", "growing_notes": "Thrives in Brisbane''s warm, humid subtropical climate. Well-adapted to Queensland conditions. Requires well-draining soil and full sun. Good heat tolerance. Introduced to Australia from Thailand.", "availability": "Available at specialized tropical fruit nurseries in Queensland including Daley''s Fruit Tree Nursery and other subtropical specialists.", "sort_order": 1}, {"name": "Sri Kembangan", "slug": "sri-kembangan", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Malaysia, seedling selection from Kembangan region", "traits": "Medium to large fruit 13-15cm long. Amber-yellow to orange color when ripe. Elongated shape.", "flesh_fruit": "Very sweet, juicy, firm, refreshing. Few seeds. Tropical cordial-like flavor.", "yield_notes": "Good producer, 2-3 crops per year in warm climates", "growing_notes": "Excellent for subtropical Brisbane. Heat and humidity tolerant. Seedlings grow true to type. Well-suited to Queensland''s summer rainfall pattern. Requires consistent moisture.", "availability": "Available at Heaven On Earth Fruit Trees and tropical fruit nurseries throughout Queensland.", "sort_order": 2}, {"name": "Golden Star", "slug": "golden-star", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Florida, USA, 1965. Developed at University of Florida, Homestead.", "traits": "Large, deeply winged fruit. Bright golden yellow skin, very waxy. Decorative appearance.", "flesh_fruit": "Juicy, crisp. Mildly subacid when harvested early, becomes sweet if allowed to ripen fully on tree.", "yield_notes": "Self-fertile. Bears well and regularly even as isolated tree.", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Thai Knight", "slug": "thai-knight", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Thailand, traditional selection", "traits": "Medium-sized fruit with bright orange color. Excellent visual appeal.", "flesh_fruit": "Very sweet, refreshing, juicy. Really good flavor profile.", "yield_notes": "Self-fertile, productive", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Maha", "slug": "maha", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Malaysia, traditional cultivar", "traits": "Slightly rounded fruit shape. Medium size. Sweet with low acidity.", "flesh_fruit": "Sweet, juicy, mild flavor", "yield_notes": "Good productivity. Can be picked slightly earlier than some other varieties.", "growing_notes": "Well-suited to Brisbane''s subtropical climate. Major commercial cultivar in Malaysia. Good adaptation to humid conditions. Heat tolerant.", "availability": "Available through specialized Queensland nurseries with Malaysian variety collections.", "sort_order": 5}, {"name": "Kembangan", "slug": "kembangan", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Malaysia, Kembangan region", "traits": "Sweet, juicy fruit. Almost seedless.", "flesh_fruit": "Excellent sweet flavor, very juicy", "yield_notes": "Good cropper", "growing_notes": "Excellent for Brisbane''s subtropical conditions. Tolerates summer heat and humidity well. Good for home gardens.", "availability": "Available at specialty tropical fruit nurseries in Queensland.", "sort_order": 6}, {"name": "Giant Siam", "slug": "giant-siam", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Thailand, traditional large-fruited selection", "traits": "Very large fruit, impressive size", "flesh_fruit": "Sweet, juicy", "yield_notes": "Productive", "growing_notes": "Suitable for Brisbane subtropical climate. Heat tolerant. Popular in tropical Queensland gardens.", "availability": "Available through Turner''s Garden Centre Brisbane and tropical specialists.", "sort_order": 7}, {"name": "B-10", "slug": "b-10", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Malaysia, selected cultivar", "traits": "Common Malaysian commercial variety. Finest quality and flavor.", "flesh_fruit": "Excellent sweet flavor, high quality", "yield_notes": "Produces more fruit when cross-pollinated with another variety (like B-17 or B-2)", "growing_notes": "Well-adapted to subtropical Brisbane conditions. Benefits from cross-pollination. Excellent for high-quality fruit production.", "availability": "Available from specialty nurseries with Malaysian cultivar collections.", "sort_order"