UPDATE public.garden_import_queue SET payload = '{"species": "Strawberry", "species_slug": "strawberry", "varieties": [{"name": "Red Rhapsody", "slug": "red-rhapsody", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Queensland Department of Agriculture and Fisheries (QDAF), Australia, 2000s", "traits": "Very high-yielding, winter-fruiting variety bred specifically for Southeast Queensland conditions. Medium to large conical berries with glossy red exterior and deep red interior.", "flesh_fruit": "Firm texture, sweet flavor, attractive appearance. Excellent shelf life and transport qualities.", "yield_notes": "Very high - one of the top-yielding varieties for subtropical production. Dominant commercial variety in Queensland.", "growing_notes": "", "availability": "Licensed nurseries throughout Queensland and Australia via Australasian Plant Genetics.", "sort_order": 0}, {"name": "Stella-ASBP", "slug": "stella-asbp", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australian Strawberry Breeding Program (ASBP), Queensland, 2024", "traits": "Large fruit size, bright red attractive appearance. Named after disability activist Stella Young. Shows resistance to red leaf disorder.", "flesh_fruit": "Beautiful flavor with consistent sweetness. High consumer rating in taste tests. Firm, glossy berries.", "yield_notes": "High yield, cost-effective for growers. Very productive for subtropical conditions.", "growing_notes": "", "availability": "Licensed nurseries in Queensland via Australasian Plant Genetics. Recently released (2024).", "sort_order": 1}, {"name": "Susie-ASBP (Suzie)", "slug": "susie-asbp-suzie", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australian Strawberry Breeding Program (ASBP), named after Olympic swimmer Susie O''Neill", "traits": "Large fruit with excellent quality. Produces consistently throughout the subtropical growing season.", "flesh_fruit": "Sweet, firm berries with good flavor. Attractive bright red color inside and out.", "yield_notes": "High yield with large average fruit size. Commercial viability proven.", "growing_notes": "", "availability": "Licensed nurseries via Australasian Plant Genetics throughout Australia.", "sort_order": 2}, {"name": "Sweet Charlie", "slug": "sweet-charlie", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "University of Florida, USA, 1990s", "traits": "Heat-tolerant variety developed for warm climates. Early season producer with glossy, large berries.", "flesh_fruit": "Sweet flavor with firm texture. Medium to large conical berries. Bright red color.", "yield_notes": "Good productivity, especially in subtropical and warm climates where other varieties struggle.", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Redlands Joy", "slug": "redlands-joy", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia, bred for subtropical climates", "traits": "Exceptionally large berries with sweet, juicy characteristics. Mid-season variety. Shows some rain resistance.", "flesh_fruit": "One of the sweetest strawberries in Australia. Large size, juicy texture, excellent flavor profile.", "yield_notes": "Good performer in subtropical climate. Reliable production.", "growing_notes": "", "availability": "Queensland and Australian nurseries, particularly popular in Southeast Queensland.", "sort_order": 4}, {"name": "Sugarbaby", "slug": "sugarbaby", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia, early 2000s (PBR variety)", "traits": "Mid-season variety. Exceptionally attractive red, glossy, conical berries. Large to extra-large size (20g average).", "flesh_fruit": "Bright red flesh, low acidity, excellent sweet flavor. Firm and resilient with resistance to rain damage. Received highest score in Better Berries Field Day taste tests at Redlands in 2003.", "yield_notes": "Fruit well displayed and easily harvested. Good productivity for niche market sales.", "growing_notes": "", "availability": "Propagated by Sweets Strawberry Runners. Protected by Plant Breeders Rights (PBR).", "sort_order": 5}, {"name": "Rubygem", "slug": "rubygem", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Queensland, Australia", "traits": "Short-day variety producing from late autumn through early spring into summer. Low chill requirement.", "flesh_fruit": "High yields of moderately firm, attractive, juicy and delicious red fruit.", "yield_notes": "High yield producer suitable for Southeast Queensland strawberry-growing district.", "growing_notes": "", "availability": "Queensland nurseries and specialized strawberry plant suppliers.", "sort_order": 6}, {"name": "Sundrench", "slug": "sundrench", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Queensland Department of Agriculture and Fisheries (QDAF), Australia", "traits": "Similar characteristics to Red Rhapsody with deep red exterior. High yielding variety for winter growing.", "flesh_fruit": "Deep red color throughout, good flavor and firmness.", "yield_notes": "Very high yielding for subtropical winter conditions.", "growing_notes": "", "availability": "Licensed nurseries throughout Queensland via commercial propagators.", "sort_order": 7}, {"name": "Albion", "slug": "albion", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "University of California, USA, 2006", "traits": "Day-neutral variety. Long, conical, symmetrical berries. Firm fruit bursting with sweetness. Most commonly planted variety in Victoria, Australia.", "flesh_fruit": "Very sweet with high sugar content. Large, firm berries with excellent shelf life. Consistent flavor profile.", "yield_notes": "High yields with good early season production. Produces continuously throughout growing season.", "growing_notes": "", "availability": "Widely available from Australian nurseries and online strawberry plant retailers.", "sort_order": 8}, {"name": "Festival", "slug": "festival", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "University of Florida, USA, 2000", "traits": "Short-day variety with conic-shaped fruit. Deep red, glossy exterior.", "flesh_fruit": "Bright red interior, very firm texture, excellent flavor. Good for fresh market and processing.", "yield_notes": "Medium yield with smaller fruit size compared to some other varieties tested in subtropical Queensland.", "growing_notes": "", "availability": "Available from select Australian nurseries specializing in strawberry varieties.", "sort_order": 9}, {"name": "Fortuna", "slug": "fortuna", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "California, USA", "traits": "Medium-sized berries with good appearance and firmness.", "flesh_fruit": "Good flavor, firm texture. Smaller fruit compared to some varieties.", "yield_notes": "Moderate yields suitable for commercial production in subtropical areas.", "growing_notes": "", "availability": "Specialist strawberry nurseries in Australia.", "sort_order": 10}, {"name": "Alinta", "slug": "alinta", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia, bred for Australian conditions", "traits": "Australian-bred variety producing large, glossy berries. Disease-resistant. Long fruiting period (~9 months in most areas).", "flesh_fruit": "Fine flavor, medium to large berries. Good eating quality.", "yield_notes": "Extended fruiting season provides steady production over many months.", "growing_notes": "", "availability": "Australian nurseries, particularly home garden suppliers.", "sort_order": 11}, {"name": "Tioga", "slug": "tioga", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "University of California, USA, 1950s", "traits": "Historic variety, over 50 years old. Large berries on vigorous plants.", "flesh_fruit": "Sweet fruit with good flavor. Large size, good firmness.", 